import XPVehicleSDK
import NetworkExtension
import Network

fileprivate let tag = "XPConnectWiFiManager"

@objc public class XPConnectWiFiManager: NSObject {

    public static let shared = XPConnectWiFiManager()

    public typealias ReachableBlock = () -> Bool
    // 网络状态
    public var checkIsReachableBlock: ReachableBlock?

    public enum XPConnectWiFiError: Error {
        case joinError
        case alreadyAssociated // 已连接
        case other(err: Error)
    }

    let monitor = NWPathMonitor()

    public var isWifiActive = false

    public func startMonitor() {
        monitor.pathUpdateHandler = { [weak self] path in
            self?.isWifiActive = path.usesInterfaceType(.wifi)
        }
        monitor.start(queue: DispatchQueue.global())
    }

    public func stopMonitor() {
        monitor.cancel()
    }

    @objc public class func connectToWiFi(ssid: String, password: String, result: @escaping ((Bool) -> Void)) {
        connectWiFi(ssid: ssid, password: password) {
            result($0.0)
        }
    }

    public static func connectWiFi(ssid: String, password: String, result: @escaping ((Bool, XPConnectWiFiError?)) -> Void) {

        DispatchQueue.main.asyncAfter(deadline: .now() + 0.1) {

            let isReachable = XPConnectWiFiManager.shared.checkIsReachableBlock?() ?? false

            Log.e(tag: tag, "date: \(Date()), Connect WiFi: \(ssid) with password: \(password)")
            Log.e(tag: tag, "isReachable: \(isReachable)")
        }

        let hotspotConfig = NEHotspotConfiguration(ssid: ssid, passphrase: password, isWEP: false)
        hotspotConfig.joinOnce = true

        NEHotspotConfigurationManager.shared.apply(hotspotConfig) { (hotSpotError) in
            if let error = hotSpotError {
                let err = error as NSError
                if NEHotspotConfigurationErrorDomain == err.domain, err.code == 13 {
                    Log.e(tag: tag, "Already associated. (Connected)")
                    result((true, .alreadyAssociated))
                } else {
                    Log.e(tag: tag, "An error occurred. Error: \(error)")
                    result((false, .other(err: error)))
                }
            } else {
                Log.e(tag: tag, "Successfully connected to the Wi-Fi network.")
                result((true, nil))

            }
        }
    }


}

