    public static func getRecScene(completeBlock: @escaping (_ response: VERecSceneResp?, _ isSuccess: Bool) -> Void){
        let callback: VehicleHttpRequestCallback<VERecSceneResp> = { result in
            if result.code == 200 {
                completeBlock(result.data, true)
            } else {
                completeBlock(nil, false)
            }
