// MARK: - 常量
public let kCCCProtocolTypeKey      = "CCC"
public let kICCOAProtocolTypeKey    = "ICCOA"
public let kICCEProtocolTypeKey     = "ICCE"
public let kXPBLEProtocolTypeKey    = "XPBLE"

public let kPhoneDeviceTypeKey      = "PHONE"
public let kWatchDeviceTypeKey      = "WATCH"
public let kAppletDeviceTypeKey     = "APPLET"
public let kOtherDeviceTypeKey      = "OTHER"

// MARK: - 枚举
@objc(XPBLEKeyCardStatus)
public enum BleKeyCardStatus: Int, Codable, SQLSpecificExpressible {
    case invalid        = 0  // 已失效
    case normal         = 1  // 正常
    case toBeActivated  = 2  // 待激活
    case activated      = 3  // 激活生效中
    case reportingLost  = 4  // 挂失生效中
    case reportLost     = 5  // 已挂失
    case reportingFound = 6  // 解挂生效中
    case locking        = 7  // 锁定生效中
    case locked         = 8  // 已锁定
    case unlocking      = 9  // 解锁生效中
    case blacking       = 10 // 加黑生效中
    case blacked        = 11 // 已加黑
    case unblacking     = 12 // 解黑生效中
    case removeing      = 13 // 注销生效中
    case expired        = 14 // 已过期
    case preCreated     = 15 // 预创建
}

@objc(XPBLEKeyCardType)
public enum BleKeyCardType: Int, Codable, SQLSpecificExpressible {
    case _BLEKey             = 101
    case _BLECertKey         = 102
    case _BLESelfKey         = 103
    case _BLEWatchKey        = 104
    case _WatchCertKey       = 105
    case _BLEMonaKey         = 106
    case _NFCCardKey         = 201
    case _NFCPhoneKey        = 202
    case _NFCWatchKey        = 203
    case _V3_XPBLE_PhoneKey  = 301
    case _V3_XPBLE_AppletKey = 303
    case _V3_Phone_CCCKey    = 304
    case _V3_XPBLE_OtherKey  = 305
    case _V3_Phone_ICCOAKey  = 306
    case _V3_Watch_CCCKey    = 307
    case _V3_Phone_ICCEKey   = 308
}

