fileprivate let tag = "[BleKeyCard]"

// MARK: - 模型
@objc(XPBLEKeyCard)
public final class BleKeyCard: NSObject, DBClientRecord {

    @objc public var cardNo: String = ""
    @objc public var status: BleKeyCardStatus = .normal
    @objc public var nickName: String?
    @objc public var effectiveTime: UInt64 = 0
    @objc public var validTime: UInt64 = 0
    @objc public var cardType: BleKeyCardType = ._BLEKey
    @objc public var deviceId: String?
    @objc public var shareFrom: String?
    @objc public var vin: String?
    @objc public var color: String?
    @objc public var plateNo: String?
    @objc public var model: String?
    @objc public var tel: String?
    @objc public var reason: String?
    @objc public var uid: UInt64 = 0
    @objc @DefaultFalse public var isRegisterInThisInstall: Bool
//    @objc public var isRegisterInThisInstall: Bool = false
    @objc public var createTime: UInt64 = 0
    @objc public var updateTime: UInt64 = 0
    @objc public var macAddr: String?
    @objc public var surportUWB: UInt64 = 0
    @objc public var isInCache: Bool = false

    // readonly
    @objc public var invalidTime: Int64 { Int64(validTime) * 60 * 1000 }
    @objc public var effectiveDate: Date { Date(timeIntervalSince1970: TimeInterval(effectiveTime) * 60) }
    @objc public var validDate: Date? { validTime == 0 ? nil : Date(timeIntervalSince1970: TimeInterval(invalidTime) / 1000) }
    @objc public var createDate: Date { Date(timeIntervalSince1970: TimeInterval(createTime) / 1000) }
    @objc public var updateDate: Date { Date(timeIntervalSince1970: TimeInterval(updateTime) / 1000) }
    @objc public var ssid: String {
        guard let mac = macAddr, !mac.isEmpty else { return "" }
        return "XPED-" + mac.replacingOccurrences(of: ":", with: "").uppercased()
    }

    // MARK: - GRDB
    public static var databaseTableName: String { "xpblekeycard" }

    public enum CodingKeys: String, CodingKey {
        case cardNo                    // 卡号
        case status                    // 状态
        case nickName                  // 昵称
        case effectiveTime             // 生效时间
        case validTime                 // 有效时间
        case cardType                  // 卡片类型
        case deviceId                  // 设备ID
        case shareFrom                 // 分享来源
        case vin                       // 车辆VIN码
        case color                     // 颜色
        case plateNo                   // 车牌号
        case model                     // 车型
        case tel                       // 电话
        case reason                    // 原因
        case uid                       // 用户ID
        case isRegisterInThisInstall   // 是否在当前安装中注册
        case createTime                // 创建时间
        case updateTime                // 更新时间
        case macAddr                   // MAC地址
    }

    // 定义Columns结构体，用于类型安全的列名
    public enum Columns {
        public static let cardNo                  = Column(CodingKeys.cardNo.rawValue)
        public static let status                  = Column(CodingKeys.status.rawValue)
        public static let nickName                = Column(CodingKeys.nickName.rawValue)
        public static let effectiveTime           = Column(CodingKeys.effectiveTime.rawValue)
        public static let validTime               = Column(CodingKeys.validTime.rawValue)
        public static let cardType                = Column(CodingKeys.cardType.rawValue)
        public static let tel                     = Column(CodingKeys.tel.rawValue)
        public static let reason                  = Column(CodingKeys.reason.rawValue)
        public static let shareFrom               = Column(CodingKeys.shareFrom.rawValue)
        public static let vin                     = Column(CodingKeys.vin.rawValue)
        public static let color                   = Column(CodingKeys.color.rawValue)
        public static let plateNo                 = Column(CodingKeys.plateNo.rawValue)
        public static let model                   = Column(CodingKeys.model.rawValue)
        public static let createTime              = Column(CodingKeys.createTime.rawValue)
        public static let updateTime              = Column(CodingKeys.updateTime.rawValue)
        public static let uid                     = Column(CodingKeys.uid.rawValue)
        public static let isRegisterInThisInstall = Column(CodingKeys.isRegisterInThisInstall.rawValue)
        public static let macAddr                 = Column(CodingKeys.macAddr.rawValue)
        public static let deviceId                = Column(CodingKeys.deviceId.rawValue)
    }

    public static func createTableIfNeeded(_ db: Database) throws {
        BBLog.info(tag: tag, "BleKeyCard createTableIfNeeded")
        // 创建表在 migratorIfNeeded 中统一处理
    }

    public static func migratorIfNeeded(_ migrator: DatabaseMigrator) throws -> DatabaseMigrator {
        var migrator = migrator
        BBLog.info(tag: tag, "BleKeyCard migratorIfNeeded")

        // 这里的版本号不要跟其他表的版本号冲突
        migrator.registerMigration("\(databaseTableName)_1.0.0") { db in
            BBLog.info(tag: tag, "BleKeyCard 旧数据库迁移，删除旧表 -> 创建新表 （WCDB数据库初次升级到GRDB）")

            let list: [BleKeyCard] = {
                do {
                    return try BleKeyCard.fetchAll(db)
                } catch {
                    BBLog.info(tag: tag, "fetchAll failed: $error)") // 可选：记录日志
                    return []
                }
            }()

            if (try db.tableExists(databaseTableName)) {
                try db.drop(table: databaseTableName)
            }

            try db.create(
                table: databaseTableName,
                ifNotExists: true) { table in
                    table.column(Columns.cardNo.name, .text).primaryKey(onConflict: .replace)
                    table.column(Columns.status.name, .integer).notNull().defaults(to: 1)
                    table.column(Columns.nickName.name, .text)
                    table.column(Columns.effectiveTime.name, .integer).notNull().defaults(to: 0)
                    table.column(Columns.validTime.name, .integer).notNull().defaults(to: 0)
                    table.column(Columns.cardType.name, .integer).notNull().defaults(to: 101)
                    table.column(Columns.deviceId.name, .text)
                    table.column(Columns.shareFrom.name, .text)
                    table.column(Columns.vin.name, .text)
                    table.column(Columns.color.name, .text)
                    table.column(Columns.plateNo.name, .text)
                    table.column(Columns.model.name, .text)
                    table.column(Columns.tel.name, .text)
                    table.column(Columns.reason.name, .text)
                    table.column(Columns.uid.name, .integer).notNull().defaults(to: 0)
                    table.column(Columns.isRegisterInThisInstall.name, .boolean).notNull().defaults(to: false)
                    table.column(Columns.createTime.name, .integer).notNull().defaults(to: 0)
                    table.column(Columns.updateTime.name, .integer).notNull().defaults(to: 0)
                    table.column(Columns.macAddr.name, .text)
                }

            for item in list {
                try item.insert(db)
            }
        }

        // 下次数据表升级时开启以下代码
//        migrator.registerMigration("\(databaseTableName)_1.0.1") { db in
//            BBLog.info("BleKeyCard 表结构变化，数据库迁移，新增字段")
//            try db.alter(table: "\(databaseTableName)") { t in
//                t.add(column: "age", .integer)
//            }
//        }

        return migrator
    }
}

// MARK: - 业务方法
public extension BleKeyCard {

    @objc var isWorking: Bool {
        let now = UInt64(Date().timeIntervalSince1970 * 1000)
        return status == .activated
            && effectiveTime * 60 * 1000 < now
            && now < invalidTime
    }

    @objc func isCreateInThisDevice() -> Bool {
        deviceId == UIDevice.devideId()
    }

    @objc func isValid() -> Bool {
        let isSDK2ndCar = XPVehicleSDK.shared.vehicleManager.isOpenedVehicleTypeCode(XPDBProxyHelper.shared.dbMessageProxy?.currentVehicleTypeCode() ?? "")

        if isSDK2ndCar {
            return XPVehicleSDK.currentVehicle()?.digitalKeyManager?.digitalKey(keyCardType: .SAFE) != nil
        }

        return isCreateInThisDevice() && isRegisterInThisInstall && (status == .normal || status == .activated)
    }

    @objc func isValidInOldCode() -> Bool {
        isCreateInThisDevice() && isRegisterInThisInstall && (status == .normal || status == .activated)
    }

    // MARK: 存 / 删
    @objc
    func save() -> Bool {
        do {
            try XPDBManager.client.write { db in
                if self.uid == 0 {
                    self.uid = XPVehicleSDK.shared.vehicleManager.uid
                }
                try self.insert(db, onConflict: .replace)
            }
            BBLog.info(tag: tag, "BleKeyCard save success: \(self)")
            return true
        } catch {
            BBLog.error(tag: tag, "BleKeyCard save error: \(error)")
            return false
        }
    }

    @objc
    func deleteCard() -> Bool {
        do {
            try XPDBManager.client.write { db in
                try self.delete(db)
            }
            BBLog.info(tag: tag, "BleKeyCard delete success: \(self)")
            return true
        } catch {
            BBLog.error(tag: tag, "BleKeyCard delete error: \(error)")
            return false
        }
    }

    @objc
    static func saveCards(_ cards: [BleKeyCard]) -> Bool {
        guard !cards.isEmpty else { return true }
        do {
            try XPDBManager.client.write { db in
                for card in cards {
                    if card.uid == 0 {
                        card.uid = XPVehicleSDK.shared.vehicleManager.uid
                    }
                    try card.insert(db, onConflict: .replace)
                }
            }
            BBLog.info(tag: tag, "BleKeyCard save cards success count: \(cards.count)")
            return true
        } catch {
            BBLog.error(tag: tag, "BleKeyCard saveCards error: \(error)")
            return false
        }
    }

    // MARK: 查询
    @objc
    static func localCards() -> [BleKeyCard] {
        guard XPVehicleSDK.shared.vehicleManager.uid != 0 else { return [] }
        let uid = XPVehicleSDK.shared.vehicleManager.uid
        do {
            return try XPDBManager.client.read { db in
                try BleKeyCard
                    .filter(Columns.uid == uid && Columns.status != BleKeyCardStatus.invalid.rawValue)
                    .fetchAll(db)
            } ?? []
        } catch {
            BBLog.error(tag: tag, "localCards error: \(error)")
            return []
        }
    }

    @objc
    static func localMyOwnCards(withVin vin: String) -> [BleKeyCard] {
        guard XPVehicleSDK.shared.vehicleManager.uid != 0 else { return [] }
        let uid = XPVehicleSDK.shared.vehicleManager.uid
        do {
            return try XPDBManager.client.read { db in
                try BleKeyCard
                    .filter(Columns.uid == uid
                            && Columns.vin == vin
                            && Columns.status != BleKeyCardStatus.invalid.rawValue
                            && Columns.shareFrom == "0")
                    .fetchAll(db)
            } ?? []
        } catch {
            BBLog.error(tag: tag, "localMyOwnCards error: \(error)")
            return []
        }
    }

    @objc
    static func localUserCards(withVin vin: String) -> [BleKeyCard] {
        guard XPVehicleSDK.shared.vehicleManager.uid != 0 else { return [] }
        let uid = XPVehicleSDK.shared.vehicleManager.uid
        do {
            return try XPDBManager.client.read { db in
                try BleKeyCard
                    .filter(Columns.uid == uid
                            && Columns.vin == vin
                            && Columns.status != BleKeyCardStatus.invalid.rawValue)
                    .fetchAll(db)
            } ?? []
        } catch {
            BBLog.error(tag: tag, "localUserCards error: \(error)")
            return []
        }
    }

    @objc
    static func localEmpowerCards(withVin vin: String) -> [BleKeyCard] {
        guard XPVehicleSDK.shared.vehicleManager.uid != 0 else { return [] }
        let uid = XPVehicleSDK.shared.vehicleManager.uid
        do {
            return try XPDBManager.client.read { db in
                try BleKeyCard
                    .filter(Columns.uid == uid
                            && Columns.vin == vin
                            && Columns.status != BleKeyCardStatus.invalid.rawValue
                            && Columns.shareFrom != "0")
                    .fetchAll(db)
            } ?? []
        } catch {
            BBLog.error(tag: tag, "localEmpowerCards error: \(error)")
            return []
        }
    }

    @objc
    static func getSSID(fromVin vin: String) -> String? {
        do {
            let card = try XPDBManager.client.read { db -> BleKeyCard? in
                try BleKeyCard
                    .filter(Columns.vin == vin)
                    .order(Columns.updateTime.desc)
                    .limit(1)
                    .fetchOne(db)
            }
            return card?.ssid
        } catch {
            BBLog.error(tag: tag, "getSSID error: \(error)")
            return nil
        }
    }

    // MARK: 更新
    @objc
        func updateMacaddr() -> Bool {
            guard let mac = macAddr, !mac.isEmpty else { return false }
            var ok = false
            do {
                try XPDBManager.client.write { db in
                    try BleKeyCard
                        .filter(Columns.cardNo == cardNo)
                        .updateAll(db, [
                            Columns.macAddr.set(to: mac),
                            Columns.updateTime.set(to: UInt64(Date().timeIntervalSince1970 * 1000))
                        ])
                    ok = true
                }
            } catch {
                BBLog.error(tag: tag, "updateMacaddr error: \(error)")
            }
            return ok
        }

    // MARK: 更新 isRegisterInThisInstall
    @objc
    func updateIsRegisterInThisInstall() -> Bool {
        var ok = false
        do {
            try XPDBManager.client.write { db in
                try BleKeyCard
                    .filter(Columns.cardNo == cardNo)
                    .updateAll(db, [
                        Columns.isRegisterInThisInstall.set(to: true),
                        Columns.updateTime.set(to: UInt64(Date().timeIntervalSince1970 * 1000))
                    ])
                ok = true
            }
        } catch {
            BBLog.error(tag: tag, "updateIsRegisterInThisInstall error: \(error)")
        }
        if ok { isRegisterInThisInstall = true }
        return ok
    }

    // MARK: 批量失效 / 删除
    @objc
    static func markCardInvalid(withCardNos cardNos: [String]) -> Bool {
        guard !cardNos.isEmpty else { return true }
        var ok = false
        do {
            try XPDBManager.client.write { db in
                try BleKeyCard
                    .filter(cardNos.contains(Columns.cardNo))
                    .updateAll(db, [
                        Columns.status.set(to: BleKeyCardStatus.invalid.rawValue),
                        Columns.updateTime.set(to: UInt64(Date().timeIntervalSince1970 * 1000))
                    ])
                ok = true
            }
        } catch {
            BBLog.error(tag: tag, "markCardInvalid error: \(error)")
        }
        return ok
    }

    // MARK: 根据 uid+vin+isEmpower 批量置为失效
    @objc
    static func markAllCardInvalid(uid: UInt64, vin: String, isEmpower: Bool) -> Bool {
        var ok = false
        do {
            try XPDBManager.client.write { db in
                let shareCond = isEmpower ? Columns.shareFrom != "0" :  Columns.shareFrom == "0"
                try BleKeyCard
                    .filter(Columns.uid == uid
                            && Columns.vin == vin
                            && shareCond)
                    .updateAll(db, [
                        Columns.status.set(to: BleKeyCardStatus.invalid.rawValue),
                        Columns.updateTime.set(to: UInt64(Date().timeIntervalSince1970 * 1000))
                    ])
                ok = true
            }
        } catch {
            BBLog.error(tag: tag, "markAllCardInvalid error: \(error)")
        }
        return ok
    }

    @objc
    static func deleteAllCards(uid: UInt64) -> Bool {
        do {
            try XPDBManager.client.write { db in
                try BleKeyCard.filter(Columns.uid == uid).deleteAll(db)
            }
            BBLog.info(tag: tag, "删除 uid:\(uid) 钥匙成功")
            return true
        } catch {
            BBLog.error(tag: tag, "deleteAllCards uid error: \(error)")
            return false
        }
    }

    @objc
    static func deleteAllCards(vin: String) -> Bool {
        do {
            try XPDBManager.client.write { db in
                try BleKeyCard.filter(Columns.vin == vin).deleteAll(db)
            }
            BBLog.info(tag: tag, "删除 vin:\(vin) 钥匙成功")
            return true
        } catch {
            BBLog.error(tag: tag, "deleteAllCards vin error: \(error)")
            return false
        }
    }

    @objc
    static func deleteLocalKeyList(vin: String) -> Bool {
        guard XPVehicleSDK.shared.vehicleManager.uid != 0 else { return false }
        let uid = XPVehicleSDK.shared.vehicleManager.uid
        do {
            try XPDBManager.client.write { db in
                try BleKeyCard
                    .filter(Columns.uid == uid && Columns.vin == vin)
                    .deleteAll(db)
                BBLog.info(tag: tag, "删除 vin:\(vin) 用户uid:\(uid) 钥匙成功")
            }
            return true
        } catch {
            BBLog.error(tag: tag, "deleteLocalKeyList error: \(error)")
            return false
        }
    }

    // MARK: 同步
    @objc
    static func synData(withVins vins: [String]) {
        do {
//            try XPDBManager.client.write { db in
//                for vin in vins {
//                    try BleKeyCard.filter(Columns.vin == vin).deleteAll(db)
//                }
//            }

            let allCards = try XPDBManager.client.read { db in
                try BleKeyCard
                    .filter(vins.contains(Columns.vin))
                    .fetchAll(db)
            }
            let allVins = allCards?.map { $0.vin } ?? []
            let toDelete = Set(allVins).subtracting(Set(vins))
            for vin in toDelete {
                BBLog.info(tag: tag, "待删除钥匙数据的vin: \(vin)")
                if let vin = vin {
                    deleteAllCards(vin: vin)
                }
            }
            if toDelete.isEmpty {
                BBLog.info(tag: tag, "无需同步证书钥匙报文数据")
            }
        } catch {
            BBLog.error(tag: tag, "synData error: \(error)")
        }
    }

    @objc
    static func dropCardTable() -> Bool {
        do {
            try XPDBManager.client.write { db in
                try db.drop(table: databaseTableName)
            }
            return true
        } catch {
            BBLog.error(tag: tag, "dropCardTable error: \(error)")
            return false
        }
    }

    // MARK: 单张卡置为失效
    @objc
    func markAsInvalid() -> Bool {
        var ok = false
        do {
            try XPDBManager.client.write { db in
                try BleKeyCard
                    .filter(Columns.cardNo == cardNo)
                    .updateAll(db, [
                        Columns.status.set(to: BleKeyCardStatus.invalid.rawValue),
                        Columns.updateTime.set(to: UInt64(Date().timeIntervalSince1970 * 1000))
                    ])
                ok = true
            }
        } catch {
            BBLog.error(tag: tag, "markAsInvalid error: \(error)")
        }
        if ok { status = .invalid }
        return ok
    }

    // MARK: 单张卡置为注销中
    @objc
    func markAsRemoving() -> Bool {
        var ok = false
        do {
            try XPDBManager.client.write { db in
                try BleKeyCard
                    .filter(Columns.cardNo == cardNo)
                    .updateAll(db, [
                        Columns.status.set(to: BleKeyCardStatus.removeing.rawValue),
                        Columns.updateTime.set(to: UInt64(Date().timeIntervalSince1970 * 1000))
                    ])
                ok = true
            }
        } catch {
            BBLog.error(tag: tag, "markAsRemoving error: \(error)")
        }
        if ok { status = .removeing }
        return ok
    }

    @objc
    func merge(_ card: BleKeyCard) {
        status      = card.status
        effectiveTime = card.effectiveTime
        validTime   = card.validTime
        createTime  = card.createTime
        updateTime  = card.updateTime
        deviceId    = card.deviceId
        shareFrom   = card.shareFrom
        if cardType == ._V3_XPBLE_PhoneKey {
            cardType = ._BLESelfKey
        }
    }

    @objc
    func updateVin(_ vin: String) {
        if self.vin?.isEmpty ?? true && !vin.isEmpty {
            self.vin = vin
        }
    }
}

extension BleKeyCard {
    @objc public static func modelCustomPropertyMapper() -> [String : Any]? {
        [
            "effectiveTime": "effectiveTime",
            "vin":           "vin",
            "cardNo":        "cardNo",
            "createTime":    "createTime",
            "cardType":      "cardType",
            "nickName":      "nickName",
            "validTime":     "validTime",
            "shareFrom":     "shareFrom",
            "status":        "status",
            "updateTime":    "updateTime",
            "tel":           "tel",
            "reason":        "reason"
        ]
    }

    @objc public func modelCustomTransform(from dic: [AnyHashable : Any]) -> Bool {
        // uid
        let userId = (dic["userId"] as? NSNumber)?.uint64Value ?? 0
        uid = userId == 0 ? XPVehicleSDK.shared.vehicleManager.uid : userId

        // keyId -> cardNo
        if let keyId = dic["keyId"] as? String, !keyId.isEmpty {
            cardNo = keyId
        }

        // keyName -> nickName
        if let keyName = dic["keyName"] as? String, !keyName.isEmpty {
            nickName = keyName
        }

        // phoneType -> model
        if let phoneType = dic["phoneType"] as? String, !phoneType.isEmpty {
            model = phoneType
        }

        // protocolType + deviceType -> cardType
        if let protocolType = dic["protocolType"] as? String,
           let deviceType   = dic["deviceType"]   as? String,
           !protocolType.isEmpty,
           !deviceType.isEmpty {

            switch protocolType {
            case kXPBLEProtocolTypeKey:
                switch deviceType {
                case kPhoneDeviceTypeKey:
                    cardType = ._BLESelfKey
                case kWatchDeviceTypeKey:
                    cardType = ._WatchCertKey
                case kAppletDeviceTypeKey:
                    cardType = ._V3_XPBLE_AppletKey
                default:
                    cardType = ._V3_XPBLE_OtherKey
                }
            case kCCCProtocolTypeKey:
                if deviceType == kPhoneDeviceTypeKey  { cardType = ._V3_Phone_CCCKey  }
                if deviceType == kWatchDeviceTypeKey  { cardType = ._V3_Watch_CCCKey  }
            case kICCOAProtocolTypeKey:
                cardType = ._V3_Phone_ICCOAKey
            case kICCEProtocolTypeKey:
                cardType = ._V3_Phone_ICCEKey
            default: break
            }
        }

        // keyType -> shareFrom
        if let keyType = dic["keyType"] as? String, keyType == "OWNER" {
            shareFrom = "0"
        } else {
            if shareFrom != "0" { shareFrom = "SHARED" }
        }

        // keyStatus -> status
        if let keyStatus = dic["keyStatus"] as? Int {
            status = BleKeyCardStatus(rawValue: keyStatus) ?? .normal
        }

        // 日期解析 yyyy-MM-dd HH:mm:ss
        let formatter = DateFormatter()
        formatter.dateFormat = "yyyy-MM-dd HH:mm:ss"

        if let start = dic["keyValidStart"] as? String,
           let date = formatter.date(from: start) {
            effectiveTime = UInt64(date.timeIntervalSince1970)
        }

        if let end = dic["keyValidEnd"] as? String,
           let date = formatter.date(from: end) {
            validTime = UInt64(date.timeIntervalSince1970)
        }

        // keyCapability -> surportUWB
        if let capability = dic["keyCapability"] as? [String: Any],
           let uwb = capability["uwb"] as? NSNumber {
            surportUWB = uwb.uint64Value
        }
        return true
    }
}

// MARK: - 打印
extension BleKeyCard {
    override public var description: String {
        "BleKeyCard<cardNo=\(cardNo), nickName=\(nickName ?? ""), createTime=\(createTime), updateTime=\(updateTime), status=\(status), isRegisterInThisInstall=\(isRegisterInThisInstall), macAddr=\(macAddr ?? ""), deviceId=\(deviceId ?? ""), vin=\(vin ?? ""), cardType=\(cardType), shareFrom=\(shareFrom ?? "")>"
