import Foundation
import XPVehicleSDK

class VEVeihcleSDKTool: NSObject {
    public static func uid() -> UInt64 {
        return XPVehicleSDK.shared.vehicleManager.currentVehicle()?.uid ?? 0;
    }

    public static func isLogin() -> Bool {
        return self.uid() > 0;
    }

    public static func vin() -> String {
        return XPVehicleSDK.shared.vehicleManager.currentVehicle()?.vehicleState.vin ?? "";
    }

    public static func nickName() -> String {
        return XPVehicleSDK.shared.vehicleManager.vehicleDataForVin(self.vin())?.ownerInfo?.nickName ?? "";
    }

    public static func vehicleTypeCode() -> String {
        return XPVehicleSDK.shared.vehicleManager.vehicleDataForVin(self.vin())?.vehicleTypeCode ?? "";
    }

    public static func xcomboVehicleType() -> String {
        var carType = XPVehicleSDK.shared.vehicleManager.vehicleDataForVin(self.vin())?.vehicleTypeName ?? "";
        if carType.lengthOfBytes(using: .utf8) > 0 {
            carType = self.convertLastCharacterToLowercase(str: carType)
        }
        return carType
    }

    static func convertLastCharacterToLowercase(str: String) -> String {
        guard let lastChar = str.last, lastChar.isLetter else {
            return str
        }
        var newStr = str
        newStr.removeLast()
        newStr.append(lastChar.lowercased())
        return newStr
    }

}

import Foundation
import XPVehicleSDK

extension XPVehicleExt {

    /// 行程列表
    /// - Parameters:
    ///   - vin: vin
    ///   - startTs: 查询区间开始时间
    ///   - endTs: 查询区间结束时间戳
    ///   - fetchSize: 拉取条数
    ///   - success: VehicleSuccessResponseCallback
    ///   - failure: VehicleFailedCallback
    @objc public static func requestTripList(vin: String, startTs: TimeInterval = -1, endTs: TimeInterval = -1, fetchSize: Int64 = -1, success: VehicleSuccessResponseCallbackT<TripsList>?, failure: VehicleFailedCallback<VehicleError>?) {

        let callback: VehicleHttpRequestCallback<TripsList> = { result in
            if result.code == 200 {
                Log.i(tag: "XPVehicleExt", "行程列表请求成功")
                success?(result.data)
            } else {
                Log.e(tag: "XPVehicleExt", "行程列表请求失败:", result)
                failure?(VehicleError(code: result.code, msg: result.msg))
            }
        }
        var payload: [String: Any] = ["vin": vin]

        if startTs != -1 {
            payload["startTs"] = startTs
        }
        if endTs != -1 {
            payload["endTs"] = endTs
        }
        if fetchSize != -1 {
            payload["fetchSize"] = fetchSize
        }

        VehicleHttpRequest.getRequest(path: "/flow/cv2/h5/adTripsReport/trips/list", payload: payload, callback: callback)
    }

    @objc
    /// 行程报告
    /// - Parameters:
    ///   - vin: vin
    ///   - startDate: 开始日期,yyyy-mm-dd
    ///   - endDate: 结束日期,yyyy-mm-dd
    ///   - success: success
    ///   - failure: failure
    public static func requestTripReport(vin: String, startDate: String, endDate: String, success: VehicleSuccessResponseCallbackT<TripsReportData>?, failure: VehicleFailedCallback<VehicleError>?) {

        let callback: VehicleHttpRequestCallback<TripsReportData> = { result in
            if result.code == 200 {
                Log.i(tag: "XPVehicleExt", "行程报告请求成功")
                success?(result.data)
            } else {
                Log.e(tag: "XPVehicleExt", "行程报告请求失败:", result)
                failure?(VehicleError(code: result.code, msg: result.msg))
            }
        }
        let payload: [String: Any] = ["vin": vin , "startDate": startDate, "endDate": endDate]

        VehicleHttpRequest.getRequest(path: "/flow/cv2/h5/adTripsReport/trips/summary", payload: payload, callback: callback)
    }

    @objc
    /// 行程详情
    /// - Parameters:
    ///   - vin: vin
    ///   - tripId: 行程id
    ///   - success: TripData
    ///   - failure: VehicleError
    public static func requestTripDetail(vin: String, tripId: Int64, success: VehicleSuccessResponseCallbackT<TripData>?, failure: VehicleFailedCallback<VehicleError>?) {

        let callback: VehicleHttpRequestCallback<TripData> = { result in
            if result.code == 200 {
                Log.i(tag: "XPVehicleExt", "行程详情请求成功")
                success?(result.data)
            } else {
                Log.e(tag: "XPVehicleExt", "行程详情请求失败:", result)
                failure?(VehicleError(code: result.code, msg: result.msg))
            }
        }
        let payload: [String: Any] = ["vin": vin , "tripId": tripId]

        VehicleHttpRequest.getRequest(path: "/flow/cv2/h5/adTripsReport/trips/detail", payload: payload, callback: callback)
    }

    @objc
    /// 删除行程
    /// - Parameters:
    ///   - vin: vin
    ///   - tripId: 行程id
    ///   - success: success
    ///   - failure: VehicleError
    public static func deleteTrip(vin: String, tripId: Int64, success: VehicleSuccessCallback?, failure: VehicleFailedCallback<VehicleError>?) {

        let callback: VehicleHttpRequestCallback<DefaultModel> = { result in
            if result.code == 200 {
                Log.i(tag: "XPVehicleExt", "删除行程请求成功")
                success?()
            } else {
                Log.e(tag: "XPVehicleExt", "删除行程请求失败:", result)
                failure?(VehicleError(code: result.code, msg: result.msg))
            }
        }
        var payload: [String: Any] = ["tripId": tripId]
        payload["vin"] = vin
        VehicleHttpRequest.postRequest(path: "/flow/cv2/h5/adTripsReport/trips/remove", payload: payload, callback: callback)
    }

    @objc
    /// 行程数据总览
    /// - Parameters:
    ///   - vin: vin
    ///   - success: TotalTripsReport
    ///   - failure: VehicleError
    public static func requestDriveOverview(vin: String, success: VehicleSuccessResponseCallbackT<TotalTripsReport>?, failure: VehicleFailedCallback<VehicleError>?) {

        let callback: VehicleHttpRequestCallback<TotalTripsReport> = { result in
            if result.code == 200 {
                Log.i(tag: "XPVehicleExt", "行程数据总览请求成功")
                success?(result.data)
            } else {
                Log.e(tag: "XPVehicleExt", "行程数据总览请求失败:", result)
                failure?(VehicleError(code: result.code, msg: result.msg))
            }
        }
        let payload: [String: Any] = ["vin": vin]

        VehicleHttpRequest.getRequest(path: "/flow/cv2/h5/adTripsReport/driveOverview", payload: payload, callback: callback)
    }

    @objc
    /// 查询用户是否开启了行程报告模块
    /// - Parameters:
    ///   - vin: vin
    ///   - success: TripsReportSettingModel
    ///   - failure: VehicleError
    public static func requestTripReportEnabled(vin: String, success: VehicleSuccessResponseCallbackT<TripsReportSettingModel>?, failure: VehicleFailedCallback<VehicleError>?) {

        let callback: VehicleHttpRequestCallback<TripsReportSettingModel> = { result in
            if result.code == 200 {
                Log.i(tag: "XPVehicleExt", "查询用户是否开启了行程报告模块请求成功")
                success?(result.data)
            } else {
                Log.e(tag: "XPVehicleExt", "查询用户是否开启了行程报告模块请求失败:", result)
                failure?(VehicleError(code: result.code, msg: result.msg))
            }
        }
        let payload: [String: Any] = ["vin": vin]

        VehicleHttpRequest.getRequest(path: "/flow/cv2/h5/user/adTripsReport/settings/moduleEnabled", payload: payload, callback: callback)
    }


    @objc
    /// 编辑用户设置 行程模块
    /// - Parameters:
    ///   - vin: vin
    ///   - success: VehicleSuccessCallback
    ///   - failure: VehicleError
    public static func editTripReportEnabled(vin: String, moduleEnabled: Bool, success: VehicleSuccessCallback?, failure: VehicleFailedCallback<VehicleError>?) {

        let callback: VehicleHttpRequestCallback<DefaultModel> = { result in
            if result.code == 200 {
                Log.i(tag: "XPVehicleExt", "编辑用户设置 行程模块 请求成功")
                success?()
            } else {
                Log.e(tag: "XPVehicleExt", "编辑用户设置 行程模块请求失败:", result)
                failure?(VehicleError(code: result.code, msg: result.msg))
            }
        }
        let payload: [String: Any] = ["vin": vin, "moduleEnabled": moduleEnabled]

        VehicleHttpRequest.postRequest(path: "/flow/cv2/h5/user/adTripsReport/settings/edit", payload: payload, callback: callback)
    }
}

