import Foundation
import XPVehicleSDK

extension XPVehicleExt {

    /// APP扫码获取用户权限信息
    /// - Parameters:
    ///   - qrCode: 二维码内容
    ///   - success: PermissionRequestInfoModel
    ///   - failure: error
    public static func getPermissionRequestInfo(qrCode: String? , success: VehicleSuccessResponseCallback?, failure: VehicleFailedCallback<VehicleError>?) {
        guard let qrCode = qrCode else {
            failure?(VehicleError(code: .ParamError, desc: "参数错误"))
            return
        }
        let payload = ["qrcode": qrCode] as [String : Any]

        let callback: VehicleHttpRequestCallback<PermissionRequestInfoModel> = { result in
            if result.code == 200 {
                let data = VehicleResponse(channel: .TCP)
                data.data = result.data
                success?(data)
            } else {
                failure?(VehicleError(code: result.code, msg: result.msg))
            }
        }
        VehicleHttpRequest.postRequest(path: "/sso/app/v3/qrcode/permissionInfo", payload: payload, defaultDomain: nil, callback: callback)
    }

    /// 扫码登录到车
    /// - Parameters:
    ///   - qrCode: qrCode 必选
    ///   - shouldRequestPermission: 是否需要请求权限
    ///   - success: 成功回调
    ///   - failure: 失败回调
    public static func loginOnCar(qrCode: String?, shouldRequestPermission: Bool, success: VehicleSuccessCallback?, failure: VehicleFailedCallback<VehicleError>?) {
        guard let qrCode = qrCode else {
            failure?(VehicleError(code: .ParamError, desc: "参数错误"))
            return
        }
        let permissions: [Int] = (shouldRequestPermission) ? [1] : []
        let payload = ["qrcode": qrCode,
                       "permissions": permissions] as [String : Any]

        let callback: VehicleHttpRequestCallback<DefaultModel> = { result in
            if result.code == 200 {
                success?()
            } else {
                failure?(VehicleError(code: result.code, msg: result.msg))
            }
        }
        VehicleHttpRequest.postRequest(path: "/sso/app/v3/qrcode/validate", payload: payload, defaultDomain: nil, callback: callback)
    }

    // 获取http请求需要的额外header，目前只有mona车用
    public static func extraGateWayHeaders() -> Dictionary<String, Any> {
        var backDic: [String : Any]? = CarService.getMonaGateWayHeadersSync()
        return backDic ?? [:]
    }

    // 请求哨兵视频列表
    public static func requestSentinelVideoList(_ success: VehicleSuccessResponseCallback?, failed: VehicleFailedCallback<VehicleError>?) {
       let vehicleInst = XPVehicleSDK.currentVehicle() as? BaseVehicle
       vehicleInst?.requestSentinelVideoList(success, failed: failed);
    }

    public static func requestLatestChargingRecord(vin: String? , success: VehicleSuccessResponseCallback?, failure: VehicleFailedCallback<VehicleError>?) {
        guard let vin = vin else {
            failure?(VehicleError(code: .ParamError, desc: "参数错误"))
            return
        }
        let payload = ["vin": vin] as [String : Any]

        let callback: VehicleHttpRequestCallback<LatestChargingRecordModel> = { result in
            if result.code == 200 {
                let data = VehicleResponse(channel: .TCP)
                data.data = result.data
                success?(data)
            } else {
                failure?(VehicleError(code: result.code, msg: result.msg))
            }
        }
        VehicleHttpRequest.getRequest(path: "/vmp-charging/cv2/charging/chargingRecord/latest", payload: payload, defaultDomain: nil, callback: callback)
    }

    // 请求车端OTA升级状态（仅针对不支持数字车态的车型，目前只有mona车在用）
    public static func requestOTAState(_ success: VehicleSuccessResponseCallback?, failed: VehicleFailedCallback<VehicleError>?) {
        let vehicleInst = XPVehicleSDK.currentVehicle() as? BaseVehicle
        vehicleInst?.requestOTAState(success, failed: failed);
    }
}

import Foundation
import XPVehicleSDK

extension XPVehicleExt {
    /// 仅用于小组件请求车态信息（HTTP）
    /// - Parameters:
    ///   - vin: 车驾号
    ///   - vehicleTypeCode: 车型编码
    ///   - success: VehicleState
    ///   - failure: error
    public static func requestWidgetVehicleState(vin: String, vehicleTypeCode: String, success: VehicleSuccessResponseCallback?, failure: VehicleFailedCallback<VehicleError>?) {

        let callback: VehicleHttpRequestCallback<WidgetVehicleState> = { result in
            if result.code == 200 {
                Log.i(tag: "XPVehicleExt", "小组件请求车态信息成功")
                var data = VehicleResponse(channel: .TCP)
                data.data = result.data
                success?(data)
            } else {
                Log.e(tag: "XPVehicleExt", "小组件请求车态信息失败:", result)
                failure?(VehicleError(code: result.code, msg: result.msg))
            }
        }

        VehicleHttpRequest.postRequest(path: "/biz/v5/widget/vehicle/state", payload: ["vin":vin, "vehicleTypeCode": vehicleTypeCode], defaultDomain: nil, callback: callback)
    }

}

