7	//
8	import UIKit
9	import EventKit
10	import Combine
11	import XPVehicleSDK
12	import MMKV
13	
14	fileprivate let calendarTAG = "AI日历Ext"
15	
16	public class AiCalendarSyncManager: NSObject {
17	    @objc public static let shared = AiCalendarSyncManager()
18	    
19	    private lazy var eventStore = EKEventStore()
20	    
21	    private var cancellables = Set<AnyCancellable>()
22	    private var observeCancellable: AnyCancellable?
23	    private var vehicleInfoCancelable: EventCancellable?
24	    private var extInfoCancellable: EventCancellable?
25	    private var didEnterBackground = false
26	    
27	    private var lastAiCalendarFunState: Bool = false
28	    
29	    public var isCalendarSwitchOn: Bool {
30	        getUserCalendarSyncSwitchStatus()
31	    }
32	    
33	    private override init() {
34	        super.init()
35	        
36	        addObservers()
37	    }
38	    
39	    @objc public func startService() {
40	        stopService()
41	        vehicleInfoCancelable = XPVehicleSDK.shared.vehicleManager.vehicleInfoUpdatedEvent
42	            .on {[weak self] info in
43	                guard let result = info as? Bool else { return }
44	                self?.checkVehicleInfo()
45	            }
46	        extInfoCancellable = XPVehicleSDK.shared.vehicleManager.extInfoChangedEvent
47	            .on({[weak self] _ in
48	                guard let self else { return }
49	                if self.lastAiCalendarFunState == XPVehicleSDK.currentVehicle()?.vehiclePreference.function.AI_CALENDAR {
50	                    return
51	                }
52	                self.checkVehicleInfo()
53	            })
54	        checkVehicleInfo()
55	    }
56	    
57	    private func checkVehicleInfo() {
58	        if XPVehicleSDK.currentVehicle() == nil {
59	            return
60	        }
61	        self.lastAiCalendarFunState = XPVehicleSDK.currentVehicle()?.vehiclePreference.function.AI_CALENDAR ?? false
62	        if (XPVehicleSDK.currentVehicle()?.vehiclePreference.function.AI_CALENDAR == false) {
63	            return
64	        }
65	        
66	        checkCalendarSwitchState()
67	    }
68	    
69	    @objc public func stopService() {
70	        self.lastAiCalendarFunState = false
71	        vehicleInfoCancelable?.cancel()
72	        extInfoCancellable?.cancel()
73	    }
74	    
75	    // MARK: - 通知监听
76	    
77	    func startCalendarChangeObserve() {
78	        Log.i(tag: calendarTAG, "开始监测日程数据变化")
79	        observeCancellable?.cancel()
80	        observeCancellable = NotificationCenter.default.publisher(for: .EKEventStoreChanged)
81	            .debounce(for: .seconds(10), scheduler: DispatchQueue.main)
82	            .sink(receiveCompletion: { _ in
83	                
84	            }, receiveValue: {[weak self] _ in
85	                let isInBackground = UIApplication.shared.applicationState == .background
86	                Log.i(tag: calendarTAG, "app在\(isInBackground ? "后台" : "前台")，监测到日程数据变化")
87	                self?.checkCalendarSwitchState()
88	            })
89	    }
90	    
91	    func stopCalendarChangeObserve() {
92	        observeCancellable?.cancel()
93	        Log.i(tag: calendarTAG, "停止监测日程数据变化")
94	    }
95	    
96	    private func addObservers() {
97	        NotificationCenter.default.publisher(for: UIApplication.didEnterBackgroundNotification)
98	            .sink {[weak self] _ in
99	                self?.didEnterBackground = true
100	            }
101	            .store(in: &cancellables)
102	        NotificationCenter.default.publisher(for: UIApplication.didBecomeActiveNotification)
103	            .sink {[weak self] _ in
104	                guard let self else { return }
105	                guard self.didEnterBackground else { return }
106	                self.didEnterBackground = false
107	                guard self.isCalendarSwitchOn else { return }
108	                Log.i(tag: calendarTAG, "App从后台切到前台时同步日程到云端")
109	                self.checkVehicleInfo()
110	            }
111	            .store(in: &cancellables)
112	    }
113	    
114	    // MARK: - 开关状态同步
115	    
116	    @objc public func checkCalendarSwitchState() {
117	        Log.i(tag: calendarTAG, "开始检查日历开关状态")
118	        fetchCalendarSwitchState()
119	            .catch({[weak self] error in
120	                guard let self else { return Fail<AiCalendarMetaData, CalendarError>(error: .local("无self")).eraseToAnyPublisher() }
121	                let currentState = self.getUserCalendarSyncSwitchStatus()
122	                return Future { promise in
123	                    let metaData = AiCalendarMetaData(userAuthStatus: currentState ? 1 : 0)
124	                    promise(.success(metaData))
125	                }.eraseToAnyPublisher()
126	            })
127	            .flatMap({[weak self] metaData -> AnyPublisher<AiCalendarMetaData, CalendarError> in
128	                guard let self else { return Fail<AiCalendarMetaData, CalendarError>(error: .local("无self")).eraseToAnyPublisher() }
129	                let isOn = metaData.userAuthStatus == 1
130	                if !self.getCalendarAuthorizedStatus() && isOn {
131	                    Log.i(tag: calendarTAG, "云端为开，手机日历权限关闭，向云端同步关")
132	                    self.syncCalendarSwitchState(false)
133	                    self.setUserCalendarSyncSwitchStatus(false)
134	                    return Fail<AiCalendarMetaData, CalendarError>(error: .local("日历权限已关闭")).eraseToAnyPublisher()
135	                }
136	                return Future { promise in
137	                    promise(.success(metaData))
138	                }.eraseToAnyPublisher()
139	            })
140	            .sink { competion in
141	                switch competion {
142	                case .failure(let error):
143	                    Log.i(tag: calendarTAG, "开关状态从云端同步失败，\(error.errorDescription)")
144	                case .finished:
145	                    Log.i(tag: calendarTAG, "开关状态从云端同步结束")
146	                }
147	            } receiveValue: {[weak self] metaData in
148	                let isOn = metaData.userAuthStatus == 1
149	                Log.i(tag: calendarTAG, "开关状态从云端同步成功，状态：\(isOn ? "开" : "关")")
150	                self?.setUserCalendarSyncSwitchStatus(isOn)
151	                guard isOn else { return }
152	                let isSupportOSS = XPVehicleSDK.currentVehicle()?.vehiclePreference.function.AI_CALENDAR_OSS == true
153	                let md5 = (isSupportOSS ? metaData.scheduleDataOssMd5 : metaData.scheduleDataMd5) ?? "0"
154	                self?.syncCalendarEvents(md5: md5)
155	            }
156	            .store(in: &cancellables)
157	    }
158	    
159	    func getCalendarAuthorizedStatus() -> Bool {
160	        let status = EKEventStore.authorizationStatus(for: .event)
161	        Log.i(tag: calendarTAG, "当前日历权限：\(status)")
162	        if #available(iOS 17.0, *) {
163	            return status == .fullAccess
164	        }
165	        return status == .authorized
166	    }
167	    
168	    func getUserCalendarSyncSwitchStatus() -> Bool {
169	        if XPVehicleSDK.currentVehicle() == nil {
170	            return false
171	        }
172	        return MMKV.default()!.bool(forKey: calendarSyncSwitchStatusKey(), defaultValue: false)
173	    }
174	    
175	    @objc public func setUserCalendarSyncSwitchStatus(_ status: Bool) {
176	        if XPVehicleSDK.currentVehicle() != nil {
177	            MMKV.default()!.set(status, forKey: calendarSyncSwitchStatusKey())
178	        }
179	        if status {
180	            startCalendarChangeObserve()
181	        } else {
182	            stopCalendarChangeObserve()
183	        }
184	    }
185	    
186	    func calendarSyncSwitchStatusKey() -> String {
187	        let uid = XPVehicleSDK.currentVehicle()!.uid
188	        let vin = XPVehicleSDK.currentVehicle()!.vehiclePreference.vin
189	        return "com.xp.calendarsyncswitch-\(uid)-\(vin)"
190	    }
191	    
192	    func fetchCalendarSwitchState() -> AnyPublisher<AiCalendarMetaData, CalendarError> {
193	        return Future { promise in
194	            guard let vin = XPVehicleSDK.currentVehicle()?.vehiclePreference.vin else {
195	                Log.i(tag: calendarTAG, "从云端获取状态，没有拿到车辆信息")
196	                promise(.failure(.local("无车辆信息")))
197	                return
198	            }
199	            
200	            Task {
201	                do {
202	                    let data: AiCalendarMetaData = await try AiCalendarRequestHandler.request(type: .get, path: .queryMetaData, payload: ["vin": vin])
203	                    Log.i(tag: calendarTAG, "从云端获取状态，状态：\(data.userAuthStatus == 1 ? "开" : "关"), dbMd5:\(String(describing: data.scheduleDataMd5)), ossMd5:\(String(describing: data.scheduleDataOssMd5)), 结果：成功")
204	                    promise(.success(data))
205	                } catch {
206	                    Log.i(tag: calendarTAG, "从云端获取状态，失败")
207	                    promise(.failure(error as! CalendarError))
208	                }
209	            }
210	        }.eraseToAnyPublisher()
211	    }
212	    
213	    public func syncCalendarSwitchState(_ state: Bool) -> AnyPublisher<Bool, CalendarError> {
214	        return Future { promise in
215	            guard let vin = XPVehicleSDK.currentVehicle()?.vehiclePreference.vin else {
216	                Log.i(tag: calendarTAG, "同步开关状态到云端时没有拿到车辆信息")
217	                promise(.failure(.local("无车辆信息")))
218	                return
219	            }
220	            
221	            let parameters: [String: Any] = [
222	                "vin": vin,
223	                "status": state ? 1 : 0
224	            ]
225	            
226	            let callback: (_ result: Bool, _ error: CalendarError?) -> Void = { result, error in
227	                Log.i(tag: calendarTAG, "同步开关状态到云端，状态：\(state ? "开" : "关"), 结果：\(result ? "成功" : "失败")")
228	                ProxyManger.shared.statisticsProxy?.writeMoleEvent(event: "B014", module: "P10245", data: [
229	                    "Operation": state ? 1 : 2,
230	                    "result": result ? 1 : 2
231	                ])
232	                if result {
233	                    promise(.success(true))
234	                } else {
235	                    promise(.failure(error ?? .local("未知错误")))
236	                }
237	            }
238	            
239	            Task {
240	                do {
241	                    let result = await try AiCalendarRequestHandler.request(path: .syncSwitchState, payload: parameters)
242	                    callback(result, nil)
243	                } catch {
244	                    callback(false, error as! CalendarError)
245	                }
246	            }
247	        }.eraseToAnyPublisher()
248	    }
249	    
250	    // MARK: - 日历数据上报
251	    
