//
//  AiCalendarSyncManager.swift
//  XiaoPengQiChe
//
//  Created by xpeng on 2025/6/5.
//  Copyright © 2025 xiaopeng.com. All rights reserved.
//
import UIKit
import EventKit
import Combine
import XPVehicleSDK
import MMKV

fileprivate let calendarTAG = "AI日历Ext"

public class AiCalendarSyncManager: NSObject {
    @objc public static let shared = AiCalendarSyncManager()

    private lazy var eventStore = EKEventStore()

    private var cancellables = Set<AnyCancellable>()
    private var observeCancellable: AnyCancellable?
    private var vehicleInfoCancelable: EventCancellable?
    private var extInfoCancellable: EventCancellable?
    private var didEnterBackground = false

    private var lastAiCalendarFunState: Bool = false

    public var isCalendarSwitchOn: Bool {
        getUserCalendarSyncSwitchStatus()
    }

    private override init() {
        super.init()

        addObservers()
    }

    @objc public func startService() {
        stopService()
        vehicleInfoCancelable = XPVehicleSDK.shared.vehicleManager.vehicleInfoUpdatedEvent
            .on {[weak self] info in
                guard let result = info as? Bool else { return }
                self?.checkVehicleInfo()
            }
        extInfoCancellable = XPVehicleSDK.shared.vehicleManager.extInfoChangedEvent
            .on({[weak self] _ in
                guard let self else { return }
                if self.lastAiCalendarFunState == XPVehicleSDK.currentVehicle()?.vehiclePreference.function.AI_CALENDAR {
                    return
                }
                self.checkVehicleInfo()
            })
        checkVehicleInfo()
    }

    private func checkVehicleInfo() {
        if XPVehicleSDK.currentVehicle() == nil {
            return
        }
        self.lastAiCalendarFunState = XPVehicleSDK.currentVehicle()?.vehiclePreference.function.AI_CALENDAR ?? false
        if (XPVehicleSDK.currentVehicle()?.vehiclePreference.function.AI_CALENDAR == false) {
            return
        }

        checkCalendarSwitchState()
    }

    @objc public func stopService() {
        self.lastAiCalendarFunState = false
        vehicleInfoCancelable?.cancel()
        extInfoCancellable?.cancel()
    }

    // MARK: - 通知监听

    func startCalendarChangeObserve() {
        Log.i(tag: calendarTAG, "开始监测日程数据变化")
        observeCancellable?.cancel()
        observeCancellable = NotificationCenter.default.publisher(for: .EKEventStoreChanged)
            .debounce(for: .seconds(10), scheduler: DispatchQueue.main)
            .sink(receiveCompletion: { _ in

            }, receiveValue: {[weak self] _ in
                let isInBackground = UIApplication.shared.applicationState == .background
                Log.i(tag: calendarTAG, "app在\(isInBackground ? "后台" : "前台")，监测到日程数据变化")
                self?.checkCalendarSwitchState()
            })
    }

    func stopCalendarChangeObserve() {
        observeCancellable?.cancel()
        Log.i(tag: calendarTAG, "停止监测日程数据变化")
    }

    private func addObservers() {
        NotificationCenter.default.publisher(for: UIApplication.didEnterBackgroundNotification)
            .sink {[weak self] _ in
                self?.didEnterBackground = true
            }
            .store(in: &cancellables)
        NotificationCenter.default.publisher(for: UIApplication.didBecomeActiveNotification)
            .sink {[weak self] _ in
                guard let self else { return }
                guard self.didEnterBackground else { return }
                self.didEnterBackground = false
                guard self.isCalendarSwitchOn else { return }
                Log.i(tag: calendarTAG, "App从后台切到前台时同步日程到云端")
                self.checkVehicleInfo()
            }
            .store(in: &cancellables)
    }

    // MARK: - 开关状态同步

    @objc public func checkCalendarSwitchState() {
        Log.i(tag: calendarTAG, "开始检查日历开关状态")
        fetchCalendarSwitchState()
            .catch({[weak self] error in
                guard let self else { return Fail<AiCalendarMetaData, CalendarError>(error: .local("无self")).eraseToAnyPublisher() }
                let currentState = self.getUserCalendarSyncSwitchStatus()
                return Future { promise in
                    let metaData = AiCalendarMetaData(userAuthStatus: currentState ? 1 : 0)
                    promise(.success(metaData))
                }.eraseToAnyPublisher()
            })
            .flatMap({[weak self] metaData -> AnyPublisher<AiCalendarMetaData, CalendarError> in
                guard let self else { return Fail<AiCalendarMetaData, CalendarError>(error: .local("无self")).eraseToAnyPublisher() }
                let isOn = metaData.userAuthStatus == 1
                if !self.getCalendarAuthorizedStatus() && isOn {
                    Log.i(tag: calendarTAG, "云端为开，手机日历权限关闭，向云端同步关")
                    self.syncCalendarSwitchState(false)
                    self.setUserCalendarSyncSwitchStatus(false)
                    return Fail<AiCalendarMetaData, CalendarError>(error: .local("日历权限已关闭")).eraseToAnyPublisher()
                }
                return Future { promise in
                    promise(.success(metaData))
                }.eraseToAnyPublisher()
            })
            .sink { competion in
                switch competion {
                case .failure(let error):
                    Log.i(tag: calendarTAG, "开关状态从云端同步失败，\(error.errorDescription)")
                case .finished:
                    Log.i(tag: calendarTAG, "开关状态从云端同步结束")
                }
            } receiveValue: {[weak self] metaData in
                let isOn = metaData.userAuthStatus == 1
                Log.i(tag: calendarTAG, "开关状态从云端同步成功，状态：\(isOn ? "开" : "关")")
                self?.setUserCalendarSyncSwitchStatus(isOn)
                guard isOn else { return }
                let isSupportOSS = XPVehicleSDK.currentVehicle()?.vehiclePreference.function.AI_CALENDAR_OSS == true
                let md5 = (isSupportOSS ? metaData.scheduleDataOssMd5 : metaData.scheduleDataMd5) ?? "0"
                self?.syncCalendarEvents(md5: md5)
            }
            .store(in: &cancellables)
    }

    func getCalendarAuthorizedStatus() -> Bool {
        let status = EKEventStore.authorizationStatus(for: .event)
        Log.i(tag: calendarTAG, "当前日历权限：\(status)")
        if #available(iOS 17.0, *) {
            return status == .fullAccess
        }
        return status == .authorized
    }

    func getUserCalendarSyncSwitchStatus() -> Bool {
        if XPVehicleSDK.currentVehicle() == nil {
            return false
        }
        return MMKV.default()!.bool(forKey: calendarSyncSwitchStatusKey(), defaultValue: false)
    }

    @objc public func setUserCalendarSyncSwitchStatus(_ status: Bool) {
        if XPVehicleSDK.currentVehicle() != nil {
            MMKV.default()!.set(status, forKey: calendarSyncSwitchStatusKey())
        }
        if status {
            startCalendarChangeObserve()
        } else {
            stopCalendarChangeObserve()
        }
    }

    func calendarSyncSwitchStatusKey() -> String {
        let uid = XPVehicleSDK.currentVehicle()!.uid
        let vin = XPVehicleSDK.currentVehicle()!.vehiclePreference.vin
        return "com.xp.calendarsyncswitch-\(uid)-\(vin)"
    }

    func fetchCalendarSwitchState() -> AnyPublisher<AiCalendarMetaData, CalendarError> {
        return Future { promise in
            guard let vin = XPVehicleSDK.currentVehicle()?.vehiclePreference.vin else {
                Log.i(tag: calendarTAG, "从云端获取状态，没有拿到车辆信息")
                promise(.failure(.local("无车辆信息")))
                return
            }

            Task {
                do {
                    let data: AiCalendarMetaData = await try AiCalendarRequestHandler.request(type: .get, path: .queryMetaData, payload: ["vin": vin])
                    Log.i(tag: calendarTAG, "从云端获取状态，状态：\(data.userAuthStatus == 1 ? "开" : "关"), dbMd5:\(String(describing: data.scheduleDataMd5)), ossMd5:\(String(describing: data.scheduleDataOssMd5)), 结果：成功")
                    promise(.success(data))
                } catch {
                    Log.i(tag: calendarTAG, "从云端获取状态，失败")
                    promise(.failure(error as! CalendarError))
                }
            }
        }.eraseToAnyPublisher()
    }

    public func syncCalendarSwitchState(_ state: Bool) -> AnyPublisher<Bool, CalendarError> {
        return Future { promise in
            guard let vin = XPVehicleSDK.currentVehicle()?.vehiclePreference.vin else {
                Log.i(tag: calendarTAG, "同步开关状态到云端时没有拿到车辆信息")
                promise(.failure(.local("无车辆信息")))
                return
            }

            let parameters: [String: Any] = [
                "vin": vin,
                "status": state ? 1 : 0
            ]

            let callback: (_ result: Bool, _ error: CalendarError?) -> Void = { result, error in
                Log.i(tag: calendarTAG, "同步开关状态到云端，状态：\(state ? "开" : "关"), 结果：\(result ? "成功" : "失败")")
                ProxyManger.shared.statisticsProxy?.writeMoleEvent(event: "B014", module: "P10245", data: [
                    "Operation": state ? 1 : 2,
                    "result": result ? 1 : 2
                ])
                if result {
                    promise(.success(true))
                } else {
                    promise(.failure(error ?? .local("未知错误")))
                }
            }

            Task {
                do {
                    let result = await try AiCalendarRequestHandler.request(path: .syncSwitchState, payload: parameters)
                    callback(result, nil)
                } catch {
                    callback(false, error as! CalendarError)
                }
            }
        }.eraseToAnyPublisher()
    }

    // MARK: - 日历数据上报

    public func syncCalendarEvents(md5: String? = nil) {
        DispatchQueue.global(qos: .userInitiated).async {
            self.fetchEventCalendars(eventsMd5: md5)
        }
    }

    private func fetchEventCalendars(eventsMd5: String?) {
        let calendars = eventStore.calendars(for: .event)
        Log.i(tag: calendarTAG, "获取到的系统日历数：\(calendars.count)")
        if calendars.isEmpty {
            self.eventStore = EKEventStore()
            _ = getCalendarAuthorizedStatus()
            eventStore.refreshSourcesIfNecessary()
            DispatchQueue.global().asyncAfter(deadline: .now() + 1) {
                let calendars = self.eventStore.calendars(for: .event)
                Log.i(tag: calendarTAG, "重新获取到的系统日历数：\(calendars.count)")
                self.uploadCalendarEvents(eventsMd5: eventsMd5)
            }
        } else {
            uploadCalendarEvents(eventsMd5: eventsMd5)
        }
    }

    private func uploadCalendarEvents(eventsMd5: String?) {
        Log.i(tag: calendarTAG, "开始同步日历数据到云端")

        guard let vehicle = XPVehicleSDK.currentVehicle() else { return }

        let currentDate = Date()
        guard let startDate = Calendar.current.date(byAdding: .day, value: -10, to: currentDate),
              let endDate = Calendar.current.date(byAdding: .day, value: 10, to: currentDate) else { return }

        guard let (jsonStr, dataCnt) = queryCalendarEvents(eventStore: eventStore, start: startDate, end: endDate) else {
            Log.i(tag: calendarTAG, "获取系统日历数据失败")
            return
        }

        let newEventsMd5 = jsonStr.md5()
        Log.i(tag: calendarTAG, "新日程md5：\(newEventsMd5)，旧日程md5：\(String(describing: eventsMd5))")
        guard eventsMd5 != newEventsMd5 else {
            Log.i(tag: calendarTAG, "当前日程数据与云端一致，无需同步")
            return
        }

        var schedulesString = jsonStr
        Log.i(tag: calendarTAG, "同步日程json：\(jsonStr)")
        var format = "json"
        if let compressedStr = ZipUtil.compressByZip(json: jsonStr) {
            format = "zip"
            schedulesString = compressedStr
        }

        var parameters: [String: Any] = createSyncPayload(start: startDate, end: endDate, md5: newEventsMd5, format: format)
        let completion: (_ result: Bool) -> Void = {
            Log.i(tag: calendarTAG, "同步日程到云端结果：\($0 ? "成功" : "失败")")
            ProxyManger.shared.statisticsProxy?.writeMoleEvent(event: "B144", module: "P10013", data: [
                "dataCnt": dataCnt,
                "result": "\($0 ? 1 : 2)"
            ])
        }

        // --> 判断是OSS还是http上传
        let isSupportOSS = vehicle.vehiclePreference.function.AI_CALENDAR_OSS == true
        guard isSupportOSS else {
            parameters["schedulesString"] = schedulesString
            Log.i(tag: calendarTAG, "数据直传旧方式开始同步")
            notifyServerEndByOldWay(payload: parameters, completion: completion)
            return
        }

        Log.i(tag: calendarTAG, "OSS方式开始同步")
        syncEventsByOSS(eventsString: schedulesString, parameters: parameters, completion: completion)
    }

    private func queryCalendarEvents(eventStore: EKEventStore, start: Date, end: Date) -> (String, Int)? {
        guard let customCalendars = AiCalendarDataProvider.queryPhoneCalendarEvents(eventStore: eventStore, start: start, end: end) else {
            Log.i(tag: calendarTAG, "同步失败，没有获取到日历数据")
            return nil
        }

        let dataCnt = customCalendars.reduce(0) { $0 + ($1.events?.count ?? 0) }

        let encoder = JSONEncoder()
        encoder.outputFormatting = [.sortedKeys]
        guard let data = try? encoder.encode(customCalendars), let jsonStr = String(data: data, encoding: .utf8) else {
            Log.i(tag: calendarTAG, "同步失败，json转化失败")
            return nil
        }

        Log.i(tag: calendarTAG, "获取到的日历数:\(customCalendars.count)，条数：\(dataCnt)")

        return (jsonStr, dataCnt)
    }

    private func createSyncPayload(start: Date, end: Date, md5: String, format: String) -> [String: String] {
        let formatter = DateFormatter()
        formatter.timeZone = Calendar.current.timeZone
        formatter.dateFormat = "yyyy-MM-dd"
        let start = formatter.string(from: start)
        let end = formatter.string(from: end)
        return [
            "md5": md5,
            "startDate": start,
            "endDate": end,
            "schedulesType": "ios",
            "schedulesFormat": format
        ]
    }

    private func syncEventsByOSS(eventsString: String, parameters: [String: Any], completion: @escaping (_ result: Bool) -> Void) {
        Task {
            let result: Result<GetUploadUrlData, CalendarError> = await AiCalendarRequestHandler.request(path: .getUploadUrl, payload: [:])
            switch result {
            case .success(let uploadData):
                let url = uploadData.presignedUrl
                let fileName = uploadData.fileName
                let uploadResult = await AiCalendarRequestHandler.uploadOSSFile(data: eventsString.data(using: .utf8) ?? Data(), url: url, fileName: fileName)
                if uploadResult {
                    await notifyServerEndWithOSS(payload: parameters, completion: completion)
                } else {
                    Log.i(tag: calendarTAG, "OSS上传失败")
                }
            case .failure(let error):
                return
            }
        }
    }

    private func notifyServerEndWithOSS(payload: [String: Any], completion: @escaping (_ result: Bool) -> Void) async {
        do {
            let result = try await AiCalendarRequestHandler.request(path: .uploadComplte, payload: payload)
            completion(true)
        } catch let error {
            completion(false)
        }
    }

    private func notifyServerEndByOldWay(payload: [String: Any], completion: @escaping (_ result: Bool) -> Void) {
        Task {
            do {
                let result = await try AiCalendarRequestHandler.request(path: .uploadEvents, payload: payload)
                completion(true)
            } catch {
                completion(false)
            }
        }
    }
}

