NS_INLINE NSString * plGetBleOtaEcuNameMap(NSString *ecuName) {
    if ([ecuName isEqualToString:@"BLE"]) {
        return @"main";
    } else if ([ecuName isEqualToString:@"BLEFL"]) {
        return @"left";
    } else if ([ecuName isEqualToString:@"BLEFR"]) {
        return @"right";
    } else if ([ecuName isEqualToString:@"BLER"]) {
        return @"center";
    } else if ([ecuName isEqualToString:@"BLERR"]) {
        return @"backRight";
    } else if ([ecuName isEqualToString:@"BLERL"]) {
        return @"backLeft";
    } else {
        return ecuName;
    }
}

